1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
4	const DEDUCTIBLE = 100;
5	
6	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
16	  sword: 1000,
17	  amulet: 600,
18	  staff: 800,
19	  potion: 400,
20	  rune: 250,
21	  moonstone: 250,
22	};
23	
24	interface Policy {
25	  items: any[];
26	  cap: number;
27	  payoutSoFar: number;
28	}
29	
30	export function processScenario(input: any): unknown {
31	  const results: Array<{ premium: number } | { payout: number; remainingCap: number }> = [];
32	  const policies: Policy[] = [];
33	  let quoteCount = 0;
34	  for (const step of input.steps) {
35	    if (step.op === "claim") {
36	      const policy = policies[step.policy];
37	      let payout = 0;
38	      for (const damage of step.incident.damages) {
39	        const item = policy.items.find((it) => it.type === damage.itemType);
40	        let reimbursement: number;
41	        if (item.material === "dragon") {
42	          reimbursement = damage.amount;
43	        } else if (item.enchantment >= 8) {
44	          reimbursement = damage.amount * 0.5;
45	        } else {
46	          reimbursement = damage.amount;
47	        }
48	        payout += Math.floor(reimbursement - DEDUCTIBLE);
49	      }
50	      policy.payoutSoFar += payout;
51	      results.push({ payout, remainingCap: policy.cap - policy.payoutSoFar });
52	      continue;
53	    }
54	    const items = step.items;
55	    const insuranceSum = items.reduce((s: number, it: any) => s + (INSURANCE_VALUE_BY_TYPE[it.type] ?? 0), 0);
56	    policies.push({ items, cap: 2 * insuranceSum, payoutSoFar: 0 });
57	    if (items.length === 0) {
58	      results.push({ premium: PROCESSING_FEE });
59	      quoteCount++;
60	      continue;
61	    }
62	    const countsByType: Record<string, number> = {};
63	    for (const item of items) {
64	      countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
65	    }
66	    let basePremium = 0;
67	    for (const [type, count] of Object.entries(countsByType)) {
68	      if ((type === "rune" || type === "moonstone") && count === 3) {
69	        basePremium += 60;
70	      } else {
71	        basePremium += count * BASE_PREMIUM_BY_TYPE[type];
72	      }
73	    }
74	    let itemSurcharges = 0;
75	    for (const item of items) {
76	      if (item.cursed) {
77	        itemSurcharges += BASE_PREMIUM_BY_TYPE[item.type] * 0.5;
78	      }
79	      if (item.enchantment >= 5) {
80	        itemSurcharges += BASE_PREMIUM_BY_TYPE[item.type] * 0.3;
81	      }
82	    }
83	    const loyaltyDiscount = input.customer.yearsWithMHPCO >= 2 ? basePremium * 0.2 : 0;
84	    const followUpDiscount = quoteCount > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
85	    const premium = Math.ceil(basePremium + itemSurcharges + basePremium * FIRST_INSURANCE_RATE - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
86	    results.push({ premium });
87	    quoteCount++;
88	  }
89	  return { results };
90	}
